import "jsr:@supabase/functions-js/edge-runtime.d.ts";

const OPENAI_API_KEY = Deno.env.get("OPENAI_API_KEY");
const OPENAI_BASE_URL = "https://api.openai.com/v1";
const DEFAULT_MODEL = "gpt-4o-mini";

const SYSTEM_PROMPT = `You are a nutrition assistant. The user will describe a meal in natural language, sometimes with restaurant names (e.g. Chipotle chicken bowl, McDonald's Big Mac, homemade pasta).

You MUST:
- Carefully read the full text and respect inclusions and exclusions.
- Treat phrases like 'no rice', 'without rice', 'sin arroz', 'no cheese', 'no tortilla', 'no dressing' as EXPLICIT EXCLUSIONS.
- Never include an ingredient that the user has explicitly excluded.
- Treat 'extra', 'double', 'light', 'half' as portion modifiers (e.g. 'extra chicken' = 1.5–2x normal, 'half rice' = 0.5x normal).
- If the user says 'no rice', DO NOT include rice in items[] or in totals.
- If something is not mentioned at all, you may assume a typical default for that restaurant, BUT you must NOT override explicit exclusions.

Your job:
1) Infer reasonable portion sizes if not specified.
2) Estimate calories and macros (protein_g, carbs_g, fats_g, fiber_g) for each component.
3) Split the meal into separate ingredients / components.
4) Respond ONLY with valid JSON in this format:

{
  "assumptions": "short explanation of portions and any defaults you applied",
  "items": [
    {
      "name": "item name",
      "serving_description": "portion size",
      "calories": number,
      "protein_g": number,
      "carbs_g": number,
      "fats_g": number,
      "fiber_g": number
    }
  ],
  "totals": {
    "calories": number,
    "protein_g": number,
    "carbs_g": number,
    "fats_g": number,
    "fiber_g": number
  }
}

IMPORTANT:
- Never add rice if the description contains 'no rice' or 'without rice'.
- Never add cheese if the description contains 'no cheese'.
- Obey all 'no X' / 'without X' constraints strictly.
- Do not include any explanation outside of the JSON.`;

interface RequestBody {
  userDescription: string;
  optionalPhotoInfo?: string; // base64 data URL
}

Deno.serve(async (req: Request) => {
  try {
    // Handle CORS preflight
    if (req.method === "OPTIONS") {
      return new Response(null, {
        status: 204,
        headers: {
          "Access-Control-Allow-Origin": "*",
          "Access-Control-Allow-Methods": "POST, OPTIONS",
          "Access-Control-Allow-Headers": "authorization, x-client-info, apikey, content-type",
        },
      });
    }

    if (req.method !== "POST") {
      return new Response(JSON.stringify({ error: "Method Not Allowed" }), { 
        status: 405,
        headers: { "Content-Type": "application/json" },
      });
    }

    // Check if OpenAI API key is configured
    if (!OPENAI_API_KEY) {
      console.error("[AI Meal Estimate] OPENAI_API_KEY not configured");
      return new Response(
        JSON.stringify({ 
          error: "AI service not configured. Please set OPENAI_API_KEY in Supabase secrets." 
        }), 
        { 
          status: 500,
          headers: { "Content-Type": "application/json" },
        }
      );
    }

    // Parse request body
    const body: RequestBody = await req.json();
    const { userDescription, optionalPhotoInfo } = body;

    if (!userDescription || userDescription.trim().length < 5) {
      return new Response(
        JSON.stringify({ error: "Meal description must be at least 5 characters." }), 
        { 
          status: 400,
          headers: { "Content-Type": "application/json" },
        }
      );
    }

    console.log("[AI Meal Estimate] Processing request...");
    console.log("[AI Meal Estimate] Description:", userDescription);
    console.log("[AI Meal Estimate] Has photo:", !!optionalPhotoInfo);

    // Build OpenAI chat payload
    const userContent: any[] = [
      { type: "text", text: userDescription }
    ];

    // Add image if provided
    if (optionalPhotoInfo) {
      userContent.push({
        type: "image_url",
        image_url: {
          url: optionalPhotoInfo,
          detail: "low" // Use low detail for faster processing and lower cost
        }
      });
    }

    // Call OpenAI API
    const chatRes = await fetch(`${OPENAI_BASE_URL}/chat/completions`, {
      method: "POST",
      headers: {
        "Authorization": `Bearer ${OPENAI_API_KEY}`,
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        model: DEFAULT_MODEL,
        messages: [
          { role: "system", content: SYSTEM_PROMPT },
          { role: "user", content: userContent },
        ],
        temperature: 0.3, // Lower temperature for more consistent results
        max_tokens: 1500,
        response_format: { type: "json_object" }, // Force JSON response
      }),
    });

    if (!chatRes.ok) {
      const errorText = await chatRes.text();
      console.error("[AI Meal Estimate] OpenAI API error:", errorText);

      if (chatRes.status === 429) {
        return new Response(
          JSON.stringify({ error: "Rate limit exceeded. Please try again in a moment." }), 
          { 
            status: 429,
            headers: { "Content-Type": "application/json" },
          }
        );
      }

      return new Response(
        JSON.stringify({ error: "AI service error. Please try again." }), 
        { 
          status: 502,
          headers: { "Content-Type": "application/json" },
        }
      );
    }

    const chatResponse: any = await chatRes.json();
    const aiText = chatResponse?.choices?.[0]?.message?.content;

    if (!aiText) {
      console.error("[AI Meal Estimate] Empty response from OpenAI");
      return new Response(
        JSON.stringify({ error: "Empty response from AI service." }), 
        { 
          status: 502,
          headers: { "Content-Type": "application/json" },
        }
      );
    }

    console.log("[AI Meal Estimate] AI response received");

    // Parse the JSON response
    let parsedResponse;
    try {
      parsedResponse = JSON.parse(aiText);
    } catch (parseError) {
      console.error("[AI Meal Estimate] Failed to parse AI response:", aiText);
      return new Response(
        JSON.stringify({ error: "Invalid response format from AI service." }), 
        { 
          status: 502,
          headers: { "Content-Type": "application/json" },
        }
      );
    }

    // Validate response structure
    if (!parsedResponse.assumptions || !parsedResponse.items || !Array.isArray(parsedResponse.items) || !parsedResponse.totals) {
      console.error("[AI Meal Estimate] Invalid response structure:", parsedResponse);
      return new Response(
        JSON.stringify({ error: "Invalid response structure from AI service." }), 
        { 
          status: 502,
          headers: { "Content-Type": "application/json" },
        }
      );
    }

    // Add AI model info to response
    const finalResponse = {
      ...parsedResponse,
      aiModel: DEFAULT_MODEL,
    };

    console.log("[AI Meal Estimate] Success! Items:", finalResponse.items.length);

    return new Response(
      JSON.stringify(finalResponse), 
      { 
        status: 200,
        headers: { 
          "Content-Type": "application/json",
          "Access-Control-Allow-Origin": "*",
        },
      }
    );
  } catch (error: any) {
    console.error("[AI Meal Estimate] Unhandled error:", error);
    return new Response(
      JSON.stringify({ 
        error: "Internal server error",
        detail: error?.message || "Unknown error"
      }), 
      { 
        status: 500,
        headers: { "Content-Type": "application/json" },
      }
    );
  }
});

