        content: SYSTEM_PROMPT,
      },
      {
        role: "user",
        content: userDescription + (optionalPhotoInfo ? "\n\n[Note: User provided an image of the meal, but image analysis is not available with this model. Please estimate based on the text description.]" : ""),
      },
    ];

    // Format for Llama 3.2 chat template
    let formattedPrompt = "<|begin_of_text|>";
    for (const msg of messages) {
      formattedPrompt += `<|start_header_id|>${msg.role}<|end_header_id|>\n\n${msg.content}<|eot_id|>`;
    }
    formattedPrompt += "<|start_header_id|>assistant<|end_header_id|>\n\n";

    console.log("[AI Meal Estimate] Calling Hugging Face API...");
