// utils/publishConfig.ts

import * as appConfig from '../app.json';

export interface PublishConfig {
  name: string;
  bundleId: string;
}

export function validatePublishConfig(config: PublishConfig): string[] {
  const errors: string[] = [];

  if (!config.name || config.name.trim() === '') {
    errors.push('App Name is required.');
  }

  if (!config.bundleId || config.bundleId.trim() === '') {
    errors.push('Bundle ID is required.');
  } else if (!/^[a-zA-Z0-9.-]+$/.test(config.bundleId)) {
    errors.push('Bundle ID must contain only alphanumeric characters, periods, and hyphens.');
  }

  return errors;
}

export function getInitialPublishConfig(): PublishConfig {
  return {
    name: appConfig.expo.name || '',
    bundleId: appConfig.expo.ios?.bundleIdentifier || appConfig.expo.android?.package || '',
  };
}
```

