-- Create foods table
CREATE TABLE IF NOT EXISTS foods (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  name text NOT NULL,
  brand text,
  serving_amount numeric NOT NULL,
  serving_unit text NOT NULL,
  calories numeric NOT NULL,
  protein numeric NOT NULL,
  carbs numeric NOT NULL,
  fats numeric NOT NULL,
  fiber numeric NOT NULL DEFAULT 0,
  barcode text,
  user_created boolean DEFAULT false,
  created_by uuid REFERENCES auth.users(id),
  created_at timestamptz DEFAULT now(),
  updated_at timestamptz DEFAULT now()
);

-- Create meals table
CREATE TABLE IF NOT EXISTS meals (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id uuid NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  date date NOT NULL,
  meal_type text NOT NULL CHECK (meal_type IN ('breakfast', 'lunch', 'dinner', 'snack')),
  created_at timestamptz DEFAULT now(),
  updated_at timestamptz DEFAULT now(),
  UNIQUE(user_id, date, meal_type)
);

-- Create meal_items table
CREATE TABLE IF NOT EXISTS meal_items (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  meal_id uuid NOT NULL REFERENCES meals(id) ON DELETE CASCADE,
  food_id uuid NOT NULL REFERENCES foods(id) ON DELETE CASCADE,
  quantity numeric NOT NULL DEFAULT 1,
  calories numeric NOT NULL,
  protein numeric NOT NULL,
  carbs numeric NOT NULL,
  fats numeric NOT NULL,
  fiber numeric NOT NULL DEFAULT 0,
  created_at timestamptz DEFAULT now()
);

-- Create daily_summary table
CREATE TABLE IF NOT EXISTS daily_summary (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id uuid NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  date date NOT NULL,
  total_calories numeric DEFAULT 0,
  total_protein numeric DEFAULT 0,
  total_carbs numeric DEFAULT 0,
  total_fats numeric DEFAULT 0,
  total_fiber numeric DEFAULT 0,
  water_ml integer DEFAULT 0,
  weight numeric,
  created_at timestamptz DEFAULT now(),
  updated_at timestamptz DEFAULT now(),
  UNIQUE(user_id, date)
);

-- Enable RLS
ALTER TABLE foods ENABLE ROW LEVEL SECURITY;
ALTER TABLE meals ENABLE ROW LEVEL SECURITY;
ALTER TABLE meal_items ENABLE ROW LEVEL SECURITY;
ALTER TABLE daily_summary ENABLE ROW LEVEL SECURITY;

-- RLS Policies for foods
CREATE POLICY "Anyone can view foods" ON foods FOR SELECT USING (true);
CREATE POLICY "Users can create their own foods" ON foods FOR INSERT WITH CHECK (created_by = auth.uid());
CREATE POLICY "Users can update their own foods" ON foods FOR UPDATE USING (created_by = auth.uid());
CREATE POLICY "Users can delete their own foods" ON foods FOR DELETE USING (created_by = auth.uid());

-- RLS Policies for meals
CREATE POLICY "Users can view their own meals" ON meals FOR SELECT USING (user_id = auth.uid());
CREATE POLICY "Users can create their own meals" ON meals FOR INSERT WITH CHECK (user_id = auth.uid());
CREATE POLICY "Users can update their own meals" ON meals FOR UPDATE USING (user_id = auth.uid());
CREATE POLICY "Users can delete their own meals" ON meals FOR DELETE USING (user_id = auth.uid());

-- RLS Policies for meal_items
CREATE POLICY "Users can view their own meal items" ON meal_items FOR SELECT USING (
  EXISTS (SELECT 1 FROM meals WHERE meals.id = meal_items.meal_id AND meals.user_id = auth.uid())
);
CREATE POLICY "Users can create their own meal items" ON meal_items FOR INSERT WITH CHECK (
  EXISTS (SELECT 1 FROM meals WHERE meals.id = meal_items.meal_id AND meals.user_id = auth.uid())
);
CREATE POLICY "Users can update their own meal items" ON meal_items FOR UPDATE USING (
  EXISTS (SELECT 1 FROM meals WHERE meals.id = meal_items.meal_id AND meals.user_id = auth.uid())
);
CREATE POLICY "Users can delete their own meal items" ON meal_items FOR DELETE USING (
  EXISTS (SELECT 1 FROM meals WHERE meals.id = meal_items.meal_id AND meals.user_id = auth.uid())
);

-- RLS Policies for daily_summary
CREATE POLICY "Users can view their own daily summary" ON daily_summary FOR SELECT USING (user_id = auth.uid());
CREATE POLICY "Users can create their own daily summary" ON daily_summary FOR INSERT WITH CHECK (user_id = auth.uid());
CREATE POLICY "Users can update their own daily summary" ON daily_summary FOR UPDATE USING (user_id = auth.uid());
CREATE POLICY "Users can delete their own daily summary" ON daily_summary FOR DELETE USING (user_id = auth.uid());

-- Create indexes for better performance
CREATE INDEX IF NOT EXISTS idx_meals_user_date ON meals(user_id, date);
CREATE INDEX IF NOT EXISTS idx_meal_items_meal_id ON meal_items(meal_id);
CREATE INDEX IF NOT EXISTS idx_daily_summary_user_date ON daily_summary(user_id, date);
CREATE INDEX IF NOT EXISTS idx_foods_barcode ON foods(barcode) WHERE barcode IS NOT NULL;

-- Add FDC ID and data type to foods table
ALTER TABLE foods 
ADD COLUMN IF NOT EXISTS fdc_id bigint,
ADD COLUMN IF NOT EXISTS data_type text;

-- Add index on fdc_id for faster lookups
CREATE INDEX IF NOT EXISTS idx_foods_fdc_id ON foods(fdc_id);

-- Add comment
COMMENT ON COLUMN foods.fdc_id IS 'FoodData Central ID for foods from USDA database';
COMMENT ON COLUMN foods.data_type IS 'FDC data type: Branded, Foundation, Survey (FNDDS), SR Legacy';

-- Create my_meals table
create table my_meals (
  id uuid primary key default gen_random_uuid(),
  user_id uuid references auth.users(id) on delete cascade not null,
  name text not null,
  note text,
  created_at timestamptz default now(),
  updated_at timestamptz default now()
);

-- Create my_meal_items table
create table my_meal_items (
  id uuid primary key default gen_random_uuid(),
  my_meal_id uuid references my_meals(id) on delete cascade not null,
  food_source text not null check (food_source in ('library', 'barcode', 'quickadd', 'ai', 'custom')),
  food_id uuid references foods(id) on delete set null,
  barcode text,
  ai_snapshot_id text,
  food_name text not null,
  brand text,
  amount_grams numeric not null,
  amount_display text not null,
  per100_calories numeric not null,
  per100_protein numeric not null,
  per100_carbs numeric not null,
  per100_fat numeric not null,
  per100_fiber numeric default 0,
  created_at timestamptz default now(),
  updated_at timestamptz default now()
);

-- Enable RLS
alter table my_meals enable row level security;
alter table my_meal_items enable row level security;

-- RLS policies for my_meals
create policy "Users can view their own meals"
  on my_meals for select
  using (auth.uid() = user_id);

create policy "Users can insert their own meals"
  on my_meals for insert
  with check (auth.uid() = user_id);

create policy "Users can update their own meals"
  on my_meals for update
  using (auth.uid() = user_id);

create policy "Users can delete their own meals"
  on my_meals for delete
  using (auth.uid() = user_id);

-- RLS policies for my_meal_items
create policy "Users can view items of their own meals"
  on my_meal_items for select
  using (
    exists (
      select 1 from my_meals
      where my_meals.id = my_meal_items.my_meal_id
      and my_meals.user_id = auth.uid()
    )
  );

create policy "Users can insert items to their own meals"
  on my_meal_items for insert
  with check (
    exists (
      select 1 from my_meals
      where my_meals.id = my_meal_items.my_meal_id
      and my_meals.user_id = auth.uid()
    )
  );

create policy "Users can update items of their own meals"
  on my_meal_items for update
  using (
    exists (
      select 1 from my_meals
      where my_meals.id = my_meal_items.my_meal_id
      and my_meals.user_id = auth.uid()
    )
  );

create policy "Users can delete items of their own meals"
  on my_meal_items for delete
  using (
    exists (
      select 1 from my_meals
      where my_meals.id = my_meal_items.my_meal_id
      and my_meals.user_id = auth.uid()
    )
  );

-- Create indexes for performance
create index idx_my_meals_user_id on my_meals(user_id);
create index idx_my_meal_items_my_meal_id on my_meal_items(my_meal_id);
create index idx_my_meal_items_food_id on my_meal_items(food_id);

